var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"세상에… 이게 누구인가?","JPN":"おやまあ……これはこれは！","ENG":"Good heavens... Look who it is!","TWN":"我的天……這是誰啊？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"오랜만에 뵙는군요, 촌장님.","JPN":"お久しぶりです、村長。","ENG":"It's been a while, Chief.","TWN":"許久不見，村長。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그동안 잘 지내셨습니까?","JPN":"お元気にしていらっしゃいましたか？","ENG":"Have you been well?","TWN":"這段時間過得好嗎？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"말도 마라. 그동안 관리국에서 사람을 보내서 어찌나 고생이었는지.","JPN":"いや、今まで管理局から何度も人が来て大変だったぞ。","ENG":"Don't get me started. The Administration sent someone over, and it was a mess.","TWN":"別提了。這段時間管理局派來的人讓我吃了不少苦頭。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"교수님의 거처가 어디냐고 물어보는데, 무슨 일이 생긴 줄 알고 내가 다 조마조마했다.","JPN":"教授の居場所をしつこく聞いてくるもんだから、何かあったのかとヒヤヒヤしたんだが。","ENG":"They were asking about the Professor's whereabouts, and I was worried something might've happened.","TWN":"有人問教授的住處在哪裡，我還以為出了什麼事，緊張得不得了。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"너나 오빠도 요새 연락이 통 안되었으니…….","JPN":"お前たち兄妹も最近はまるで音沙汰がなかったしな……","ENG":"Neither you nor your brother had been in touch lately...","TWN":"你和哥哥最近也一直聯絡不上……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"죄송합니다. 근래 들어 바빴던 지라 연락할 틈이 없었군요.","JPN":"すみません。近頃は忙しくて、連絡をする余裕もありませんでした。","ENG":"I apologize. Things have been hectic lately, and I haven't had a chance to reach out.","TWN":"抱歉，最近比較忙，沒時間聯絡你。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"버밍엄 교수님의 일은… 아마 관리국에서 협조를 요청할 일이 있었나 봅니다.","JPN":"バーミンガム教授の件は……たぶん、管理局から何か協力要請でもあったんでしょう。","ENG":"As for Professor Birmingham... I imagine the Administration needed his cooperation with something.","TWN":"伯明罕教授的事情……可能是管理局請求協助的事情吧。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"큰 일은 아닐 테니 촌장님께서 걱정하실 필요는 없을 것 같군요.","JPN":"大事ではないと思いますし、村長が心配されることはありません。","ENG":"It likely wasn't anything serious, so there's no need for concern.","TWN":"這不是什麼大事，村長你不必擔心。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"하긴, 걱정할 사람이 따로 있지. 늙은이가 괜한 오지랖을 부렸구만.","JPN":"ふむ……私が心配することでもなかったか。年寄りがお節介を焼いてしまったな。","ENG":"True. I suppose it's not my place to worry. Just an old man meddling where he shouldn't.","TWN":"也是，該擔心的人另有其人。老頭子真是多管閒事了。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"교수님이야 당연하고, 기사단장인 네 오빠에게 별 일이야 있겠어?","JPN":"教授もそうだが、騎士団長を務めるお前の兄さんに何かあるわけもなかろう。","ENG":"It's not like anything could happen to the professor or to your brother, the captain.","TWN":"教授當然沒問題，你哥哥作為騎士團長會有什麼事呢？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……예. 그렇죠.","JPN":"……はい、もちろんです。","ENG":"...Yes, of course.","TWN":"……是的。沒錯。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"오랜만에 왔으니, 어떠냐. 마을 사람들을 모아 밥이라도 먹는 건?","JPN":"久しぶりに戻ったんだ。どうだ？　村の者を集めて、食事でも一緒にしないか？","ENG":"Now that you're back, how about it? Shall we gather the villagers and have a meal together?","TWN":"好久不見，怎麼樣？要不要召集村民們一起吃頓飯？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"죄송합니다. 당장 급한 일이 있어 그것부터 처리해야 할 것 같군요.","JPN":"申し訳ありません。急ぎの用事がありまして、まずそちらを片付けねばならないのです。","ENG":"I'm sorry. There's something urgent I need to take care of first.","TWN":"對不起。我有急事需要馬上處理。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"오늘은 버밍엄 교수님의 거처에 용무가 있어 찾아왔습니다.","JPN":"今日はバーミンガム教授の家に用があって参りました。","ENG":"I came to check the professor's residence today.","TWN":"今天我有事要去拜訪伯明罕教授的住處。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"열렸네. 이제 들어가봐도 좋아.","JPN":"開いたぞ、入りなさい。","ENG":"It's open. You can go in.","TWN":"開了。現在可以進去看看了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"감사합니다, 촌장님.","JPN":"ありがとうございます、村長。","ENG":"Thank you, Chief.","TWN":"好的，村長。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"감사 인사는 됐네. 바쁜데 얼굴 비추러 와준 것만해도 고맙지.","JPN":"礼はいらん。忙しい中、顔を見せてくれただけでもありがたい。","ENG":"No need to thank me. I appreciate you even stopping by when you're so busy.","TWN":"道謝就不必了。你能在百忙之中抽空來見我，我已經很感激了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"교수님이 돌아오기 힘들 것 같다며 열쇠를 맡기셨을 땐 무슨 일인가 싶어 불안했는데…….","JPN":"教授がもう戻れそうにないからと鍵を預けていったときには、何事かと心配になったが……","ENG":"When the Professor handed me the key saying he might not return, I feared the worst...","TWN":"教授說他可能無法回來，把鑰匙交給我時，我感到不安，不知道發生了什麼事……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"자네가 이렇게 소식을 전해줬으니, 오늘은 마음 편히 잠들 수 있겠어.","JPN":"お前がこうして来てくれたわけだし、今夜はぐっすり眠れそうだ。","ENG":"But now that you've brought news, I can finally rest easy tonight.","TWN":"既然你帶來了這個消息，今天我可以安心入睡了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"이런, 내가 바쁜 사람을 붙잡았구만.","JPN":"おっと、忙しい人を引き留めてしまったな。","ENG":"Oh dear, I've been holding up someone who's busy.","TWN":"哎呀，我耽誤了忙人的時間。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"늙은이는 이만 가볼 테니 편히 둘러보게.","JPN":"年寄りはこの辺で失礼するよ。ゆっくり見ていきなさい。","ENG":"I'll get going. Take your time looking around.","TWN":"我這把老骨頭就先走了，你們隨意看看吧。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"알렌 경의 방 답지 않게, 먼지가 자욱하군.","JPN":"アレン卿の部屋らしくもない、すっかり埃まみれだな。","ENG":"This doesn't feel like Sir Allen's room at all. So dusty...","TWN":"艾倫卿的房間不像平時那樣，滿是灰塵。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"청소. 자주 하라 말했으면서…….","JPN":"掃除はこまめにしろとあれだけ私に小言を言っておいて……","ENG":"He always said to keep it clean...","TWN":"打掃。明明說過要經常打掃的……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"정신 차려. 추억이나 회상하려고 여기까지 온 게 아니야.","JPN":"いや、しっかりしろ。思い出に浸るためにここに来たわけじゃない。","ENG":"Focus. I didn't come here to wallow in nostalgia.","TWN":"振作點。我們不是來這裡追憶往事的。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"무언가… 단서가 될만한 걸 찾아야 해.","JPN":"何か……手がかりになりそうなものを見つけるんだ。","ENG":"I need... to find something. Anything that could be a clue.","TWN":"我必須找到一些能成為線索的東西。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"클리포트 게임 이후 구원기사단과 레드시프트의 유착관계가 대두되었지만…….","JPN":"クリフォトゲーム以来、救世騎士団とレッドシフトの癒着が問題視されてきたけれど……","ENG":"After the Qliphoth Game, rumors spread about ties between the Knights of Redemption and Red Shift...","TWN":"逆卡巴拉遊戲之後，救贖騎士團與紅移的勾結關係浮出水面……"},"stage":{"bg":"WOODHOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L48_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"나와 오빠를 블루시프트로 후견해준 건 다름아닌 알렌 경이야.","JPN":"私と兄をブルーシフトへ入れるようにしてくれたのは、ほかならぬアレン卿だ。","ENG":"But it was Sir Allen who sponsored me and my brother into Blue Shift.","TWN":"我和哥哥被藍移收養，正是因為艾倫卿的幫助。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"만약 그들 사이에 접점이 있었다면, 적어도 우릴 레드시프트로 보냈겠지.","JPN":"もしレッドシフトとの間に接点があったのなら、私たちはレッドシフトに送られていたはず。","ENG":"If there had been any real link, he would've sent us to Red Shift instead.","TWN":"如果他們之間有交集的話，至少會把我們送到紅移。"},"stage":{"bg":"CHURCH_KNIGHT","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ALLEN_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그러니 그 확률이 희박함에도… 오빠는 기사단을 떠난 뒤 이곳으로 향했다.","JPN":"だから、可能性が低いとわかっていても……兄は騎士団を離れてこの地へ向かった。","ENG":"And yet, even with that unlikely connection... my brother came here after leaving the Order.","TWN":"所以即使那個機率很低……哥哥還是在離開騎士團後前往了這裡。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"단순히 고향이 그리워서? 그게 아니면, 레드시프트의 흔적이 이곳으로 이어진 건가?","JPN":"ただ故郷が恋しかったから？　それとも、レッドシフトの痕跡がこの地に繋がっていたのか？","ENG":"Was it just homesickness? Or did he follow traces of Red Shift here?","TWN":"只是因為想念故鄉嗎？還是說，紅移的痕跡延續到了這裡？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"UI_DIVE","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……모르겠군.","JPN":"……わからない。","ENG":"...I can't tell.","TWN":"……我不知道。"},"stage":{"bg":"WOODHOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"무언가 단서가 남아있지 않을까 싶었는데. 역시 너무 늦어버린 건가?","JPN":"何か手がかりが残っていればと思ったが……やはり遅すぎたのか？","ENG":"I hoped there'd be some clue left behind, but maybe... I was too late.","TWN":"我以為會留下什麼線索，但果然還是太晚了嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"에, 에스테로사! 거기 있느냐?","JPN":"エ、エステロサ！　そこにいるか！？","ENG":"E-Esterosa! Are you there?","TWN":"艾、艾斯特洛索！在那裡嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"촌장님? 갑자기 무슨 일이십니까?","JPN":"村長？　急にどうされたんですか？","ENG":"Chief? What's going on?","TWN":"村長？突然發生了什麼事？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"크, 큰일이다. 갑자기 주변이 이상해졌어!","JPN":"た、大変だ！　突然辺りの様子がおかしくなった！","ENG":"S-something terrible's happening. The area's gone strange!","TWN":"出，出大事了。周圍突然變得奇怪了！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"주변이 이상해졌다니. 그게 무슨 소리십니까?","JPN":"辺りの様子が……？　どういうことですか？","ENG":"Strange? What do you mean?","TWN":"周圍變得奇怪了？這是什麼意思？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……뭐야.","JPN":"……なんだこれは。","ENG":"...What?","TWN":"……什麼呀。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"사람들이… 하늘로 솟구치고 있어?","JPN":"人々が……空に浮かび上がっている！？","ENG":"People... are rising into the sky?","TWN":"人們……漂浮在空中？"},"stage":{"bg":"MS_1203","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_MOVEMENT_03"},{"id":"L21_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"주변에 영향을 미칠 정도의 고준위 침식파. 이건, 설마…!","JPN":"周囲にまで影響が出るほどの高レベル侵食波。これは、まさか……！","ENG":"A high-level Corruption ray affecting the surroundings... This is...?!","TWN":"周圍受到影響的高強度侵蝕波。這難道是…！"},"stage":{"bg":"MS_1203","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"아니, 아니야. 그때 그 그림자조차 주변에 눈이 내리는 게 전부였어!","JPN":"いや、違う！　あの時のシャドウでさえ、まわりに雪が降っただけだった！","ENG":"No, it can't be. Even that Shadow back then only caused snowfall!","TWN":"不，不是的。那時即使是暗影，周圍也只是下著雪而已！"},"stage":{"bg":"WOODHOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L24_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"대체 무슨 일이 일어난 거지…?!","JPN":"いったい何が起きている……！？","ENG":"What on earth is happening...?!","TWN":"到底發生了什麼事……？！"},"stage":{"bg":"WOODHOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"이것은 관리국에서 시민 여러분들께 송출하는 행동 요령 안내입니다.","JPN":"これは管理局から市民の皆様に伝える、行動指針のご案内です。","ENG":"This is a safety announcement for citizens from the Administration.","TWN":"<color=#ffd34c>這是管理局向各位市民發送的行動要領。</color>"},"stage":{"bg":"WOODHOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"가능한 실내에 머무르시고 실외에서는 절대 하늘을 바라보지 마십시오.","JPN":"できる限り室内にいて、屋外では決して空を見上げないようにしてください。","ENG":"Stay indoors as much as possible, and never look up at the sky when outdoors.","TWN":"<color=#ffd34c>請儘量待在室內，在室外絕對不要抬頭看天空。</color>"},"stage":{"bg":"WOODHOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"안전을 위해 절대 대피소를 벗어나지 마시고, 관리국의 지침을 따라주십시오.","JPN":"安全のため決して避難所を離れず、管理局の行動指針に従ってください。","ENG":"For your safety, follow the Administration's guidelines and do not leave the shelter.","TWN":"<color=#ffd34c>為保安全，千萬不要離開避難所，請聽從管理局的指示。</color>"},"stage":{"bg":"WOODHOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"해당 지침은 경보해제시까지 유효합니다.","JPN":"この行動指針は警報が解除されるまで有効です。","ENG":"The guidelines will remain in effect until the disaster alert is lifted.","TWN":"<color=#ffd34c>該指令將持續到警報解除。</color>"},"stage":{"bg":"WOODHOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"제길…!!","JPN":"くそ……！！","ENG":"Damn it...!","TWN":"可惡……！！"},"stage":{"bg":"WOODHOUSE","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_SIREN_02"},{"id":"L34_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"촌장님! 괜찮으십니까?","JPN":"村長！　大丈夫ですか？","ENG":"Chief! Are you all right?","TWN":"村長！你沒事吧？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"허, 허리가 굽은 게 이런 식으로 도움이 될 줄은 몰랐구나. 다행히 실외에서는 하늘을 보지 않았어.","JPN":"ま、曲がった腰がこんな形で役に立つとはな。幸い、外では空を見てない。","ENG":"W-who knew having a hunched back would have its perks. Thankfully, I can't look up, so I'm safe for now.","TWN":"沒想到彎腰竟然能這樣派上用場。幸好在室外沒有抬頭看天。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"다만 주민들 중 몇 명이 보이지 않는다. 대체 이걸 어떡해야…….","JPN":"ただ、村の者の何人かが見当たらない。いったい、どうすれば……","ENG":"But some villagers are missing. What are we supposed to do about this...?","TWN":"只是有些居民看不到。到底該怎麼辦……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"침착하시죠. 경보해제까지 실내에만 계시면 큰 문제는 없을 겁니다.","JPN":"落ち着いてください。警報が解除されるまでは屋内にいてくだされば、大きな問題にはならないはずです。","ENG":"Stay calm. As long as you remain indoors until the alert is lifted, you should be safe.","TWN":"請保持冷靜。在警報解除之前，只要待在室內就不會有大問題。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"우선-.","JPN":"まずは……","ENG":"For now...","TWN":"首先……"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"CHIEF_MEMORIAL_NULL_NULL","text":{"KOREA":"마, 말도 안 돼! 침식체가 왜 마을까지?","JPN":"ば、馬鹿な！　侵食体がどうして村にまで！？","ENG":"I-impossible! C.O.s in the village?","TWN":"不、不可能吧！侵蝕體怎麼會到村子裡？"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"……아무래도 현상의 영향을 받은 건 인간만이 아닌 것 같군요.","JPN":"……どうやら、この現象の影響を受けたのは人間だけではないようですね。","ENG":"...It seems this phenomenon isn't only affecting people.","TWN":"……看來不僅僅是人類受到了現象的影響。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"침식체는 제가 막겠습니다.","JPN":"侵食体は、私が食い止めます。","ENG":"I'll deal with the C.O.s.","TWN":"侵蝕體由我來擋著。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"촌장님께서는 안전한 곳으로 주민들을 대피시키시죠.","JPN":"村長は、安全な場所へ住民の避難をお願いします。","ENG":"Chief, please evacuate the villagers to a safe location.","TWN":"村長，請把居民們轉移到安全的地方吧。"},"stage":{"bg":"PRIDE_COUNTRY","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};